/**
 * trending-loader.js — The Tech Brief
 * ────────────────────────────────────────────────────────────────
 * Reads assets/data/trending.json (generated by build_trending in build.py)
 * Renders full magazine-style article cards:
 *  - Hero image (Unsplash, copyright-free)
 *  - Category badge + headline + intro
 *  - "Read full article ▾" expands to FULL 700+ word article inline
 *  - "Open full article →" links to dedicated article page
 * ────────────────────────────────────────────────────────────────
 */

(function () {
  'use strict';

  var JSON_PATH = 'assets/data/trending.json';

  /* ── Inject styles ─────────────────────────────────────────── */
  function injectStyles() {
    if (document.getElementById('ttb-ts')) return;
    var s = document.createElement('style');
    s.id = 'ttb-ts';
    s.textContent = [
      /* Section wrapper */
      '.trending-now{background:#FFFBF5;border-top:3px solid var(--accent,#2563EB);border-bottom:1px solid #E0D8CF;padding:0;margin:0;}',
      '.trending-inner{max-width:1280px;margin:0 auto;padding:36px 24px 44px;}',

      /* Header */
      '.trending-meta{display:flex;align-items:center;gap:16px;margin-bottom:32px;flex-wrap:wrap;}',
      '.trending-live{display:flex;align-items:center;gap:6px;}',
      '.live-dot{width:9px;height:9px;background:#22C55E;border-radius:50%;display:inline-block;animation:ttb-pulse 1.8s ease-in-out infinite;}',
      '@keyframes ttb-pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.5;transform:scale(1.3)}}',
      '.live-label{font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#22C55E;font-family:var(--font-mono,monospace);}',
      '.trending-title{font-family:var(--font-serif,"DM Serif Display",Georgia,serif);font-size:24px;font-weight:400;color:var(--ink,#0D0D12);margin:0;}',
      '.trending-date{font-size:12px;color:var(--ink-3,#7A7A8C);margin-left:auto;font-family:var(--font-mono,monospace);}',

      /* Grid */
      '.tgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;list-style:none;margin:0;padding:0;}',
      '@media(max-width:960px){.tgrid{grid-template-columns:repeat(2,1fr);}}',
      '@media(max-width:560px){.tgrid{grid-template-columns:1fr;}}',

      /* Card */
      '.tcard{background:#fff;border-radius:12px;border:1px solid #E0D8CF;overflow:hidden;display:flex;flex-direction:column;box-shadow:0 2px 8px rgba(0,0,0,.06);transition:transform .2s,box-shadow .2s;}',
      '.tcard:hover{transform:translateY(-3px);box-shadow:0 6px 24px rgba(0,0,0,.1);}',

      /* Image */
      '.tcard-img{width:100%;height:200px;object-fit:cover;display:block;background:#EEE;}',

      /* Body */
      '.tcard-body{padding:18px 20px 12px;flex:1;display:flex;flex-direction:column;gap:10px;}',
      '.tcard-meta-row{display:flex;align-items:center;gap:10px;}',
      '.tcard-num{font-size:12px;font-weight:700;color:var(--ink-3,#7A7A8C);font-family:var(--font-mono,monospace);flex-shrink:0;}',
      '.tcard-badge{display:inline-block;color:#fff;font-size:10px;font-weight:700;letter-spacing:.8px;text-transform:uppercase;padding:3px 9px;border-radius:999px;}',
      '.tcard-cat{font-size:11px;color:var(--ink-3,#7A7A8C);margin-left:auto;}',

      /* Headline */
      '.tcard-headline{font-family:var(--font-serif,"DM Serif Display",Georgia,serif);font-size:17px;line-height:1.3;color:var(--ink,#0D0D12);margin:0;}',
      '.tcard-headline a{color:inherit;text-decoration:none;}',
      '.tcard-headline a:hover{color:var(--accent,#2563EB);}',

      /* Intro (always visible) */
      '.tcard-intro{font-size:13.5px;line-height:1.65;color:var(--ink-2,#3D3D4E);margin:0;}',

      /* Key insight */
      '.tcard-insight{background:#EEF4FF;border-left:3px solid var(--accent,#2563EB);padding:10px 14px;border-radius:0 6px 6px 0;font-size:12.5px;font-style:italic;color:var(--ink,#0D0D12);line-height:1.55;}',
      '.tcard-insight strong{display:block;font-size:10px;text-transform:uppercase;letter-spacing:.8px;color:var(--accent,#2563EB);font-style:normal;margin-bottom:4px;}',

      /* Full article expansion */
      '.tcard-full{display:none;flex-direction:column;gap:0;margin-top:6px;border-top:2px solid var(--accent,#2563EB);padding-top:16px;}',
      '.tcard-full.open{display:flex;}',
      '.tcard-full-inner{display:flex;flex-direction:column;gap:14px;}',
      '.tcard-full-inner p{font-size:14.5px;line-height:1.82;color:var(--ink,#0D0D12);margin:0;}',
      '.tcard-full-inner h4{font-family:var(--font-serif,"DM Serif Display",Georgia,serif);font-size:16px;color:var(--ink,#0D0D12);margin:8px 0 0;border-top:1px solid #E5E5EE;padding-top:12px;}',
      '.tcard-conclusion-box{background:#F5F8FF;border-left:3px solid var(--accent,#2563EB);padding:12px 16px;border-radius:0 8px 8px 0;font-size:13.5px;font-style:italic;color:var(--ink,#0D0D12);line-height:1.65;margin-top:4px;}',
      '.tcard-open-link{display:inline-flex;align-items:center;gap:5px;font-size:13px;font-weight:700;color:var(--accent,#2563EB);text-decoration:none;margin-top:8px;padding:8px 0;border-top:1px solid #E0D8CF;}',
      '.tcard-open-link:hover{color:var(--accent-h,#1D4ED8);}',

      /* Footer */
      '.tcard-footer{padding:12px 20px;border-top:1px solid #E0D8CF;background:#FAFAF7;display:flex;align-items:center;justify-content:space-between;gap:8px;flex-wrap:wrap;}',
      '.tcard-expand{background:none;border:none;cursor:pointer;font-size:13px;font-weight:700;color:var(--accent,#2563EB);font-family:var(--font-body,inherit);padding:0;display:flex;align-items:center;gap:4px;}',
      '.tcard-expand:hover{color:var(--accent-h,#1D4ED8);}',
      '.tcard-expand-icon{display:inline-block;transition:transform .25s;font-style:normal;font-size:11px;}',
      '.tcard-expand.expanded .tcard-expand-icon{transform:rotate(180deg);}',
      '.tcard-date{font-size:11px;color:var(--ink-3,#7A7A8C);font-family:var(--font-mono,monospace);}',

      /* Footer browse link */
      '.trending-footer{margin-top:32px;text-align:right;}',
      '.trending-cta{font-size:13px;font-weight:700;color:var(--accent,#2563EB);text-decoration:none;letter-spacing:.3px;}',
      '.trending-cta:hover{color:var(--accent-h,#1D4ED8);}',

      /* Skeleton */
      '.tcard-skel{background:#fff;border-radius:12px;border:1px solid #E0D8CF;overflow:hidden;}',
      '.skel-img{width:100%;height:200px;background:linear-gradient(90deg,#EEE 25%,#F5F5F5 50%,#EEE 75%);background-size:200% 100%;animation:ttb-shimmer 1.4s infinite;}',
      '.skel-body{padding:18px 20px;display:flex;flex-direction:column;gap:10px;}',
      '.skel-line{height:13px;border-radius:4px;background:linear-gradient(90deg,#EEE 25%,#F5F5F5 50%,#EEE 75%);background-size:200% 100%;animation:ttb-shimmer 1.4s infinite;}',
      '@keyframes ttb-shimmer{to{background-position:-200% 0}}',
    ].join('');
    document.head.appendChild(s);
  }

  /* ── Helpers ───────────────────────────────────────────────── */
  function esc(s) {
    return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }
  function fmtDate(iso) {
    try {
      var d=new Date(iso),m=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
      return m[d.getUTCMonth()]+' '+d.getUTCDate()+', '+d.getUTCFullYear();
    } catch(e){return iso||'';}
  }
  function todayLabel() {
    var d=new Date(),days=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'],m=['January','February','March','April','May','June','July','August','September','October','November','December'];
    return days[d.getDay()]+', '+d.getDate()+' '+m[d.getMonth()]+' '+d.getFullYear();
  }

  /* ── Build paragraphs from various data formats ────────────── */
  function buildParagraphsHTML(story) {
    var html = '';

    // Format 1: paragraphs array (generate_trending.py output)
    if (Array.isArray(story.paragraphs) && story.paragraphs.length > 0) {
      story.paragraphs.forEach(function(p) {
        if (p && p.trim()) html += '<p>' + esc(p.trim()) + '</p>';
      });
      return html;
    }

    // Format 2: body string split by double newline (build_trending output)
    if (story.body && typeof story.body === 'string' && story.body.trim()) {
      var paras = story.body.split(/\n\n+/).filter(function(p){ return p.trim(); });
      paras.forEach(function(p) {
        // Check if it looks like a subheading (short, no period)
        var trimmed = p.trim();
        if (trimmed.length < 80 && trimmed.indexOf('.') === -1 && trimmed.indexOf(',') === -1) {
          html += '<h4>' + esc(trimmed) + '</h4>';
        } else {
          html += '<p>' + esc(trimmed) + '</p>';
        }
      });
      return html;
    }

    // Format 3: sections array (generate_articles.py format)
    if (Array.isArray(story.sections) && story.sections.length > 0) {
      story.sections.forEach(function(sec) {
        if (sec.h2) html += '<h4>' + esc(sec.h2) + '</h4>';
        if (Array.isArray(sec.paragraphs)) {
          sec.paragraphs.forEach(function(p) {
            html += '<p>' + esc(p) + '</p>';
          });
        }
      });
      return html;
    }

    return '';
  }

  /* ── Build a single story card ─────────────────────────────── */
  function buildCard(story, index) {
    var li = document.createElement('li');
    li.className = 'tcard';

    var num        = String(index+1).padStart(2,'0');
    var badgeColor = story.badge_color || '#2563EB';
    var date       = fmtDate(story.date || '');

    // Article URL: prefer dedicated article page, fall back to category page
    var articleUrl = story.article_url || story.cat_url || 'index.html';
    var catUrl     = story.cat_url || 'index.html';

    var fullHTML   = buildParagraphsHTML(story);
    var hasContent = fullHTML.trim().length > 0;
    var hasFull    = hasContent || (story.conclusion && story.conclusion.trim());

    li.innerHTML =
      (story.image ? '<img class="tcard-img" src="'+esc(story.image)+'" alt="'+esc(story.headline)+'" loading="lazy" width="400" height="200">' : '') +
      '<div class="tcard-body">' +
        '<div class="tcard-meta-row">' +
          '<span class="tcard-num">'+num+'</span>' +
          '<span class="tcard-badge" style="background:'+badgeColor+'">'+esc(story.badge||'Tech')+'</span>' +
          '<span class="tcard-cat">'+esc(story.category||'')+'</span>' +
        '</div>' +
        '<h3 class="tcard-headline"><a href="'+esc(articleUrl)+'">'+esc(story.headline)+'</a></h3>' +
        '<p class="tcard-intro">'+esc(story.intro||story.summary||'')+'</p>' +
        (story.key_insight ? '<div class="tcard-insight"><strong>Key Insight</strong>'+esc(story.key_insight)+'</div>' : '') +
        (hasFull ?
          '<div class="tcard-full" id="tf-'+index+'">' +
            '<div class="tcard-full-inner">' +
              fullHTML +
              (story.conclusion ? '<div class="tcard-conclusion-box">'+esc(story.conclusion)+'</div>' : '') +
            '</div>' +
            (articleUrl !== catUrl ?
              '<a href="'+esc(articleUrl)+'" class="tcard-open-link">Open full article on site &#8594;</a>' : '') +
          '</div>'
        : '') +
      '</div>' +
      '<div class="tcard-footer">' +
        (hasFull ?
          '<button class="tcard-expand" data-target="tf-'+index+'" aria-expanded="false">' +
          'Read full article <i class="tcard-expand-icon" aria-hidden="true">&#9660;</i>' +
          '</button>'
        : '<a href="'+esc(catUrl)+'" style="font-size:13px;font-weight:700;color:var(--accent,#2563EB)">View '+esc(story.category||'category')+' &#8594;</a>') +
        '<span class="tcard-date">'+date+'</span>' +
      '</div>';

    // Expand/collapse toggle
    var btn = li.querySelector('.tcard-expand');
    if (btn) {
      btn.addEventListener('click', function() {
        var fullDiv = document.getElementById(this.getAttribute('data-target'));
        if (!fullDiv) return;
        var isOpen = fullDiv.classList.toggle('open');
        this.classList.toggle('expanded', isOpen);
        this.setAttribute('aria-expanded', isOpen);
        this.innerHTML = (isOpen ? 'Collapse &#9650;' : 'Read full article <i class="tcard-expand-icon" aria-hidden="true">&#9660;</i>');
      });
    }

    return li;
  }

  /* ── Skeletons ─────────────────────────────────────────────── */
  function showSkeletons(list, n) {
    for (var i=0; i<n; i++) {
      var li = document.createElement('li');
      li.className = 'tcard-skel';
      li.innerHTML = '<div class="skel-img"></div><div class="skel-body"><div class="skel-line" style="width:30%"></div><div class="skel-line" style="width:85%"></div><div class="skel-line" style="width:70%"></div><div class="skel-line" style="width:90%"></div><div class="skel-line" style="width:55%"></div></div>';
      list.appendChild(li);
    }
  }

  /* ── Rebuild the whole section from JSON ───────────────────── */
  function renderSection(section, stories) {
    section.innerHTML =
      '<div class="trending-inner">' +
        '<div class="trending-meta">' +
          '<div class="trending-live"><span class="live-dot" aria-hidden="true"></span><span class="live-label">Live</span></div>' +
          '<h2 class="trending-title">Tech Trending Now</h2>' +
          '<time class="trending-date" datetime="'+new Date().toISOString().split('T')[0]+'">'+todayLabel()+'</time>' +
        '</div>' +
        '<ol class="tgrid" aria-label="Trending stories" id="ttb-tlist"></ol>' +
        '<div class="trending-footer"><a href="ai-news.html" class="trending-cta">Browse all tech coverage &#8594;</a></div>' +
      '</div>';

    var list = section.querySelector('#ttb-tlist');
    if (!list) return;
    showSkeletons(list, 3);
    setTimeout(function() {
      list.innerHTML = '';
      stories.slice(0,6).forEach(function(s,i){ list.appendChild(buildCard(s,i)); });
    }, 300);
  }

  /* ── Main ──────────────────────────────────────────────────── */
  function run() {
    var section = document.querySelector('.trending-now');
    if (!section) return;
    injectStyles();

    // Show skeletons immediately
    var existingList = section.querySelector('.trending-list');
    if (existingList) showSkeletons(existingList, 3);

    // Try trending.json first (full article content)
    fetch(JSON_PATH+'?v='+Date.now())
      .then(function(r){ if(!r.ok) throw new Error('no json'); return r.json(); })
      .then(function(data){
        if (data && Array.isArray(data.stories) && data.stories.length > 0) {
          renderSection(section, data.stories);
        } else {
          throw new Error('empty');
        }
      })
      .catch(function(){
        // Fallback: trending.txt (simple 5-line format)
        fetch('assets/data/trending.txt?v='+Date.now())
          .then(function(r){ return r.text(); })
          .then(function(raw){
            var lines = raw.replace(/\r\n/g,'\n').split('\n');
            var block=[], stories=[];
            lines.forEach(function(line){
              var l=line.trim();
              if(l===''){
                if(block.length>=3) stories.push({headline:block[0],intro:block[1],badge:block[2],category:block[3]||'',cat_url:block[4]||'index.html',badge_color:'#2563EB',date:'',paragraphs:[],body:block[1]});
                block=[];
              } else { block.push(l); }
            });
            if(block.length>=3) stories.push({headline:block[0],intro:block[1],badge:block[2],category:block[3]||'',cat_url:block[4]||'index.html',badge_color:'#2563EB',date:'',paragraphs:[],body:block[1]});
            if(stories.length>0) renderSection(section, stories);
          })
          .catch(function(){});
      });
  }

  if (document.readyState==='loading') {
    document.addEventListener('DOMContentLoaded', run);
  } else { run(); }

})();
